SELECT MAX(close) AS max_close_price
FROM candlesticks
WHERE instrument_id = 1 AND market_id = 1 AND close_time BETWEEN '2023-05-01' AND '2023-05-31';

SELECT qav
FROM qavs
WHERE instrument_id = 1;

SELECT AVG(taker_bba) AS average_taker_bba
FROM taker_bbas
WHERE instrument_id = 0;

SELECT taker_bba
FROM taker_bbas
WHERE instrument_id = 0;

SELECT AVG(volume) AS average_volume
FROM candlesticks
WHERE instrument_id = 0;

SELECT COUNT(*) AS qav_count
FROM qavs
WHERE instrument_id = 1;

SELECT taker_bqav
FROM taker_bqavs
WHERE data_source = 'NASDAQ';

SELECT MAX(taker_bqav) AS max_taker_bqav
FROM taker_bqavs
WHERE instrument_id = 1;

SELECT AVG(close) AS average_close_price
FROM candlesticks
WHERE instrument_id = 0 AND market_id = 1;

SELECT candlestick_interval
FROM candlesticks
WHERE candlestick_id = 1;
